INSERT INTO `plants` (`p_id`, `p_name`, `p_image`, `price`, `instock`, `season`, `description`) VALUES
(1, 'ပိန်းပန်း', 'ပိန်းပန်း.png', 12000, 48, 'Hot Season', 'ပိန်းပန်း \r\nပိန်းပန်း သည် မေလတွင် ပွင့်လေ့ရှိသော ပန်း တစ်မျိုးဖြစ်သည်။\r\n\r\n မြေအနေအထား\r\n • အပူပိုင်းဒေသများ တွင် လွန်စွာအောင်မြင်စွာကြီးထွားနိုင်သည်။\r\n • နေရောင်လုံလောက်ပြီး ရေစိမ့်နိုင်သော မြေတွင် အကောင်းဆုံးပွင့်နိုင်သည်။\r\n • သဲနုမြေ နှင့်ရေလွှမ်းခြင်းမဖြစ်သောနေရာများတွင်လည်း ကြီးထွားတတ်သည်။\r\n\r\n ပွင့်ချိန်\r\n • ပိန်းပန်းသည် တစ်နှစ်တာထဲတွင် နွေရာသီ (ဧပြီ – မေ) တွင် ပွင့်လေ့ရှိသည်။\r\n • မိုးခေါင်သည့် အချိန်တွင် ပန်းများအပြည့် ငွားငွားစွင့်စွင့်လှပစွာ ပွင့်လေ့ရှိသည်။\r\n • သစ်ရွက်များကြွေပြီးနောက် ပန်းများသာကျန်ရှိပြီး  ကြာရှည်ခံသည်။\r\n\r\n ရာသီနှင့် အသုံးဝင်မှု\r\n• မိုးရာသီမတိုင်ခင် ပွင့်သောကြောင့် “မိုးခေါင်ပန်း” ဟုလည်း ခေါ်သည်။\r\n • အလှပန်းအနေနှင့်သာမက  ဆေးဖက်ဝင်အပင်အဖြစ်လည်း အသုံးပြုနိုင်သော အပင် ဖြစ်သည်။\r\n\r\n စိုက်ပျိုးခြင်းနှင့် ပြုစုနည်း\r\n • နေရောင်အပြည့်ရတဲ့နေရာတွင် စိုက်ပါ။\r\n • သဘာဝအတိုင်း ပေါက်နိုင်ပေမဲ့ အပင်သန်မာဖို့ ရေလောင်းပေးဖို့ လိုအပ်ပါတယ်။\r\n • ပန်းဖူးများ ပိုမိုအောင်မြင်စွာ ပွင့်စေချင်ရင် တစ်နှစ်တစ်ကြိမ် အပင်ကိုင်း ဖြတ်ပေးနိုင်တယ်။\r\n\r\n'),
(2, 'ဂျပန်မီးပုံးပန်း', 'japanmeeponepan.jpg', 5000, 47, 'Cold Season', 'ဂျပန်မီးပုံးပန်း ဟုခေါ်ကြသော ပန်းသည် တစ်ခါတစ်ရံ Winter Cherry ဟုလည်း သိကြသည်။ အနီရောင်သီးများက မီးပုံးပုံစံနဲ့တူသည့်အတွက် “ဂျပန်မီးပုံးပန်း” လို့လဲခေါ်သည်။\r\n\r\nမြေအနေအထား\r\n • နေရောင်လုံလောက်ပြီး အရိပ်အနည်းငယ်ရသောနေရာများတွင် အကောင်းဆုံးကြီးထွားနိုင်သည်။\r\n • မြေညစ်ကင်းပြီး ရေစိမ့်နိုင်မှုကောင်းသော သဲနုမြေတွင်စိုက်ပျိုးသင့်သည်။\r\n • မြေအေးသောနေရာများတွင် ပိုမိုကောင်းမွန်စွာပေါက်နိုင်သည်။\r\n\r\n ပွင့်ချိန်\r\n • ဤပန်းသည် နွေဦးနှင့် နွေရာသီ တွင် ပွင့်လာတတ်သည်။\r\n • ပန်းပွင့်ပြီးနောက်တွင် နွေရာသီအကုန်မှ မိုးပေါ်အလယ်ပိုင်းအထိ အသီးထွက်လာသည်။\r\n\r\n ရာသီနှင့် အသုံးဝင်မှု\r\n • ဂျပန်မီးပုံးပန်းသည် နွေဦး၊ နွေရာသီနှင့် ဆောင်းဦးရာသီ တွင်ပွင့်တတ်ပြီး မီးပုံးပုံစံသောရှိသောအနီရောင်သီးများသည် ဆောင်းရာသီအထိ ဆက်လက်တည်ရှိနေတတ်သည်။\r\n • အိမ်တွင်းအလှဆင်ခြင်း၊ ပန်းအလှဆင်ခြင်းပြုလုပ်ရန် အသုံးများသည်။\r\n\r\n စိုက်ပျိုးခြင်းနှင့် ပြုစုနည်း\r\n • နေရောင်လုံလောက်သောနေရာတွင် စိုက်ပျိုးရန်။\r\n • ရေလွှမ်းမှုမဖြစ်ရအောင် စိုက်ပျိုးရန် (မြေစိုစွတ်လွန်းပါက အမြစ်ပုပ်နိုင်သည်)။\r\n • ပျိုးပင်ပုံစံကို ထိန်းသိမ်းရန် အလျားတိုတို ဖြတ်ပေးရန်။\r\n • မြေသားအာဟာရဖြည့်စွမ်းရန် မြေသြဇာထည့်ပေးနိုင်ပါသည်။\r\n\r\nနောက်ထပ် အသုံးဝင်မှု\r\n • ဤပန်း၏ အနီရောင်သီးများသည် အလှဆင်မှုများ မှာအလွန်သင့်တော်သည်။\r\n • တချို့နိုင်ငံများတွင် ဆေးဖက်ဝင်အပင် အဖြစ် အသုံးပြုကြသည်။\r\n • အိမ်တွင်းပန်းအလှ အဖြစ်လည်း အသုံးများသည်။\r\n'),
(3, 'တရုတ်စကားပန်း ', 'tayatsakar.jpg', 9000, 47, 'Cold Season', 'တရုတ်စကားပန်း သည် လှပပြီး လူကြိုက်များသောပန်းတစ်မျိုးဖြစ်သည်။ 	\r\n        မြေအနေအထား\r\n•	တရုတ်စကားပန်းသည် နေရောင်လုံလောက်စွာရရှိသောနေရာများတွင် အောင်မြင်စွာကြီးထွားနိုင်သည်။\r\n•	 မြေညစ်ကင်းပြီး ရေစီးဆင်းမှုကောင်းသော မြေဆီမြေလတ်မျိုးဖြင့်စိုက်ပျိုးသင့်သည်။\r\n•	အေးမြသောရာသီနှင့်လည်း သင့်တော်ပြီး အပူပိုင်းဒေသများတွင်လည်းစိုက်ပျိုးနိုင်သည်။\r\n\r\nပွင့်ချိန်\r\n•	တရုတ်စကားပန်းသည် ဆောင်းဦးနှင့် ဆောင်းရာသီ မတိုင်မီကပွင့်လာတတ်သည်။ \r\n•	မိုးတွင်းနောက်ပိုင်းမှ ပွင့်လာတတ်သောကြောင့် အင်္ဂလိပ်ဘာသာဖြင့် “Autumn Flower” (ဆောင်းဦးပန်း) ဟုခေါ်ကြသည်။\r\n\r\nရာသီ\r\n•	အများအားဖြင့် ဆောင်းဦးနှင့် ဆောင်းရာသီ တွင် ပွင့်လေ့ရှိသည်။ သို့သော် အပူပိုင်းဒေသများတွင် လုပ်ငန်းများကြောင့် တစ်နှစ်ပတ်လုံးစိုက်ပျိုးသောကြောင့်ပန်းရရှိနိုင်သည်။\r\n\r\nစိုက်ပျိုးခြင်းနှင့် ပြုစုနည်း\r\n • နေရောင်လုံလောက်စွာရသောနေရာတွင် စိုက်ပျိုးခြင်း။\r\n • ရေဝပ်သောနေရာထဲတွင် မစိုက်ပျိုးပါနဲ့ (ရေစိုစွတ်နေလျှင် အမြစ်ပုပ်နိုင်သည်)။\r\n • မြေဆွေးများဖြင့် မကြာခဏ မြေသားဖြည့်ခြင်း ပြုလုပ်ရန်။\r\n'),
(4, 'ကံ့ကော်ပန်း', 'kantkaw.jpg', 6000, 5, 'Hot Season', '•	ကံ့ကော်ပန်း သည် ချစ်ခြင်းမေတ္တာတရားကိုဖော်ကျူးသောအပင်တစ်မျိုးဖြစ်ပါသည် ။\r\n\r\n  မြေအနေအထား\r\n•	အပူချိန်နှင့် စိုစွတ်မှု၊ အရိပ်လုံလောက်သော မြေဖြစ်တဲ့နေရာများတွင် ပိုမိုကောင်းမွန်စွာ ကြီးထွားနိုင်သည်။\r\n\r\n  ရာသီနှင့်ပွင့်ခြင်း\r\n•	ကံ့ကော်ပန်းသည် အများအားဖြင့် နွေရာသီအတွင်း ပိုမိုပွင့်လေ့ရှိပါတယ်။\r\n\r\n အရောင်\r\n•	ကံ့ကော်ပန်း၏ပန်းများသည် အနီ၊ အဝါ၊ အပြာ အစရှိသည့်အရောင်များဖြင့် ကွဲပြားနေပါတယ်။\r\n'),
(5, 'ဆရာမပင်', 'sayarma.png', 4000, 47, 'Hot Season', 'ဆရာမပင် သည် သစ်ပင်အမျိုးအစားဖြစ်ပါတယ်။ သူ့ရဲ့ ပန်းများမှာ အလွန်အလှပပြီး၊ အရောင်က အနီ၊ အဖြူ၊ အပြာရောင်တို့ဖြစ်ပါတယ်။\r\n\r\n      မြေအနေအထား\r\n•	ဆရာမပင်သည် နေရာတိုင်းမှာ ပေါ်က်နိုင်သော်လည်း ရေရှားသောဒေသများတွင်ပါ ရှင်သန်နိုင်သည်။\r\n   \r\n   ရာသီနှင့် ပွင့်မှု\r\n•	ဆရာမပင်သည် အများအားဖြင့် နွေရာသီတွင် ပိုမိုပွင့်သောပန်းများဖြစ် သည်။\r\n   \r\n အသုံးချမှု \r\n•	အလှပန်းစိုက်ခြင်း – အိမ်ရှေ့ခြံ၊ ကျောင်းဝင်း၊ ဥယျာဉ်များတွင် အလှပန်းအဖြစ်စိုက်ကြသည်။\r\n\r\n•	ဆေးဖက်ဝင်နိုင်မှု – အချို့ဒေသများတွင် ဆေးဖက်ဝင်အပင်အဖြစ်အသုံးပြုကြသော်လည်း အချို့အစိတ်အပိုင်းများသည် အဆိပ်ရှိနိုင်သောကြောင့် သတိထားရန်လိုသည်။\r\n'),
(6, 'သနပ်ခါးပန်း', 'thanatkhar.jpg', 6000, 46, 'Rainy Season', 'သနပ်ခါးပန်း သည် အလှဆင်ပန်းများအဖြစ်ကျော်ကြားပါသည်။\r\n\r\n           မြေအနေအထား\r\n•	သနပ်ခါးပန်းသည် အပူပိုင်း ဒေသတွင် အောင်မြင်စွာကြီးထွားနိုင်သောပန်းတစ်မျိုးဖြစ်သည်။ \r\n•	လွန်စွာပူပြင်းပြီး နေရောင်ကောင်းကောင်းရသောနေရာများမှာစိုက်ပျိုးသင့်သည်။\r\n•	 မြေညစ်ကင်းသောမြေတွင်စိုက်ပျိုးရန်သင့်တော်သည်။\r\n\r\n        ပွင့်ချိန်\r\n•	သနပ်ခါးပန်းများသည် နွေရာသီတွင်ပွင့်ပါသည်။\r\n        ရာသီ\r\n•	သနပ်ခါးပန်းသည် နွေရာသီနှင့် မိုးရာသီတွင်လည်းပွင့်တတ်သည်၊ \r\n\r\nစိုက်ပျိုးခြင်းနှင့် ပြုစုနည်း\r\n•	သနပ်ခါးပန်းသည် နေရောင်လုံလောက်ပြီး မြေညစ်ကင်းသောနေရာတွင်အောင်မြင်စွာကြီးထွားနိုင်သည်။ \r\n'),
(7, 'နေကြာပန်း ', 'naykyar.jpg', 4000, 50, 'Hot Season', 'နေကြာပန်း သည် လူကြိုက်များပြီးလှပသောပန်းတစ်မျိုးဖြစ်သည်။\r\n\r\n      မြေအနေအထား:\r\n•	နေကြာပန်းသည် နေရောင်ကောင်းစွာရသောနေရာတွင် အောင်မြင်စွာကြီးထွားနိုင်ပါသည်။ \r\n\r\n      ပွင့်ချိန်\r\n•	နေကြာပန်းများဟာ နွေရာသီတစ်လျှောက်လုံးပွင့်တတ်ပြီး  အများအားဖြင့် နွေရာသီကိုလည်း အဆုံးသတ်ပါသည်။\r\n\r\n ရာသီ\r\n•	နေကြာပန်းများသည် နွေရာသီနှင့်အဓိကဆိုင်သောပန်းများဖြစ်ပြီး နေရောင်မရှိတဲ့ရာသီတွင် မပွင့်ပါ။\r\n\r\n'),
(8, 'ခေါင်ရမ်းပန်း ', 'khaungyann.jpg', 3500, 50, 'Hot Season', 'ခေါင်ရမ်းပန်း \r\n     မြေအနေအထား \r\n•	ခေါင်ရမ်းပန်းသည် အပူပိုင်းကြိုက်သောပန်းဖြစ်သည်။\r\n•	မြေညစ်ကင်းသော၊ ပူနွေးသောဒေသများတွင်သာအောင်မြင်စွာ ပွင့်တတ်ပါသည်။ \r\n\r\n      ပွင့်ချိန်\r\n•	ခေါင်ရမ်းပန်းသည် နွေရာသီတွင် အစဉ်မပြတ်ပွင့်လာနိုင်သောပန်းတစ်မျိုးဖြစ်သည်။ \r\n\r\n      ရာသီ\r\n•	နွေရာသီတွင်ကောင်းစွာပွင့်နိုင်သည်။\r\n'),
(9, 'ဂျပန်နေကြာပန်း', 'japan.jpg', 3500, 50, 'Hot Season', 'ဒီပန်းက ဂျပန်နေကြာပန်းဖြစ်ပါတယ်။ \r\n\r\n      မြေအနေအထား\r\n•	ဂျပန်နေကြာပန်းဟာ အပူပိုင်းဒေသများတွင်အောင်မြင်စွာကြီးထွားနိုင်ပြီး နေရောင်လိုအပ်သောပန်းတစ်မျိုးဖြစ်ပါတယ်။\r\n•	 ရေကောင်းစွာရရှိပြီး မြေညစ်ကင်းစွာသောမြေမျိုးတွင် ပိုသင့်တော်သည်။\r\n\r\n     ပွင့်ချိန်\r\n•	ဂျပန်နေကြာပန်းများဟာ နွေရာသီတွင်ပွင့်ပါသည်။ \r\n      \r\nရာသီ\r\n•	ဤပန်းသည် နွေရာသီမှာတွင်သာပွင့်တတ်ပါသည်။\r\n'),
(10, 'ဇလပ်စင်္ကြာပန်း', 'jas.jpg', 4000, 50, 'Hot Season', 'ဒီပန်းက ဇလပ်စင်္ကြာဖြစ်ပါတယ်။ \r\n\r\n      မြေအနေအထား\r\n•	ဇလပ်စင်္ကြာပန်းက အပူချိန်မြင့်မားသော ဒေသများတွင် ပွင့်တတ်ပါတယ်။ \r\n•	နေရောင်ကောင်းပြီး  ရေမမြုပ်တဲ့ မြေမျိုးကိုကြိုက်ပါတယ်။\r\n\r\n      ပွင့်ချိန်\r\n•	ဇလပ်စင်္ကြာပန်းတွေဟာ  နွေရာသီမှာပွင့်တတ်ပါတယ်။ \r\n•	ဒါပေမဲ့ တချို့နေရာများတွင် ပန်းပွင့်တာကို တစ်နှစ်တာလုံးလည်းတွေ့နိုင်ပါတယ်၊ အထူးသဖြင့် အပူပိုင်းဒေသများမှာ။\r\n\r\n       ရာသီ\r\n•	ဇလပ်စင်္ကြာပန်းဟာ အပူပိုင်း၊ နွေရာသီများထဲမှာသာပွင့်လေ့ရှိသည်။\r\n'),
(11, 'နှင်းဆီပန်း', 'rose.jpg', 7000, 50, 'Cold Season', 'နှင်းဆီပန်းသည် လှပပြီး မွှေးကြိုင်သောကြောင့် လူကြိုက်များသည့် ပန်းမျိုးဖြစ်သည်။\r\n\r\n မြေအနေအထား\r\n • ရေစိမ့်ဝင်နိုင်မှုကောင်းသည့် ရွံ့မြေများ (သို့မဟုတ်) သဲမြေများ တွင် ကြီးထွားမှုကောင်းသည်။\r\n\r\n ရာသီအလိုက် ပွင့်မှု\r\n • နှင်းဆီပန်းသည် ပွင့်နိုင်စွမ်းမြင့်ပြီး တစ်နှစ်ပတ်လုံး ပွင့်နိုင်သော်လည်း နွေဦး  နှင့် ဆောင်းဦး တွင် ပန်းပွင့်နိုင်မှု ပိုမိုဖြစ်ထွန်းပါသည်။\r\n • အပူပိုမိုများလျှင် ပန်းပွင့်မှုသက်တမ်း နည်းနိုင်သဖြင့် အေးမြသောရာသီများတွင် ပိုမိုသင့်တော်သည်။\r\n\r\n ရေဖြည့်ခြင်း\r\n • မိုးမရွာသည့် ရာသီများတွင် တစ်ပတ် ၂ ကြိမ်ခန့် ရေဖျန်းပေးရန်လိုအပ်သည်။\r\n • အရိုးရှင်းဆုံးဖြစ်စေရန် မနက်အရုဏ်တွင် ရေဖြည့်ခြင်း သည် ပန်းအတွက် အထူးကောင်းမွန်သည်။\r\n\r\n ကြီးထွားမှုနှင့် ဖြတ်တောက်ခြင်း\r\n • နှင်းဆီပန်းကို ပိုမိုစိုပြေစေလိုလျှင် ပျိုးပင်ထိန်းသိမ်းမှု လုပ်ပေးရန်လိုသည်။\r\n • ဆောင်းရာသီနှောင်းပိုင်းတွင် ပင်စည်များကို ဖြတ်တောက်ပေးခြင်းသည် နောက်ထပ် ပန်းအသစ်များ ပွင့်ရန် အထောက်အကူဖြစ်စေသည်။\r\n\r\n မြေဩဇာ ထည့်ခြင်း\r\n • ပန်းပွင့်မှုများစေရန် သဘာဝမြေဩဇာ  သို့မဟုတ် အာဟာရများပြည့်စုံသော မြေဩဇာ ကို တစ်လတစ်ကြိမ် ထည့်ပေးပါ။\r\n\r\n'),
(12, 'ဇီဇဝါပန်း ', 'zi.png', 4000, 50, 'Cold Season', 'ဇီဇဝါပန်း သည် အပူပိုင်းဒေသများတွင် အလွန်ကြီးထွားသော ပန်း တစ်မျိုးဖြစ်သည်။ ပန်းရောင်စုံရှိပြီး အထူးသဖြင့် ခြံတိုင်၊ ဗီလာအလှပန်း၊ ပန်းခြံများတွင်စိုက်ဖို့ရန် လူကြိုက်များသည်။\r\n\r\n မြေအနေအထား\r\n • နေရောင်လုံလောက်စွာ ရရှိလျှင် ကောင်းစွာ ကြီးထွားနိုင်သည်။ \r\n • မြေလုံလောက်ပြီး ရေစိမ့်ဝင်မှုကောင်းသောနေရာများတွင် ပိုမိုသင့်တော်သည်။\r\n • သဲမြေ၊ ရေဆင်းမြေမျိုးတွင် ပိုမိုကြီးထွားနိုင်သည်။\r\n\r\n ပွင့်ချိန်\r\n • ဇီဇဝါပန်းသည် တစ်နှစ်ပတ်လုံး ပွင့်နိုင်သော်လည်း နွေရာသီ (မတ်-မေ) နှင့် ဆောင်းဦး (နိုဝင်ဘာ-ဇန်နဝါရီ) တွင် ပိုမိုပွင့်သည်။\r\n • မိုးရာသီတွင် ပွင့်မှုနည်းနိုင်သည်။  \r\n • ပန်းပွင့်ချိန်မှာ ရာသီအလိုက် ပြောင်းလဲနိုင်သည်။\r\n\r\nရာသီနှင့် အသုံးဝင်မှု\r\n • နွေရာသီနှင့် ဆောင်းဦးမှာ ပွင့်သောပန်းဖြစ်သည်။\r\n • ခြံတိုင်များ၊ ဗီလာ၊ ဟိုတယ်များ အလှဆင်ရာတွင် အသုံးများသည်။\r\n • အိမ်အလှပန်းခြံများတွင်လည်း စိုက်ရန် လူကြိုက်များသည်။\r\n • အပူပိုင်းဒေသများတွင် အလှဆင်ရန် အလွန်သင့်တော်သည်။\r\n\r\n စိုက်ပျိုးခြင်းနှင့် ပြုစုနည်း\r\n • အပူပိုင်းဒေသများတွင် ကြီးထွားနိုင်မှုကောင်းသည်။\r\n • နေရောင်လုံလောက်သောနေရာတွင် စိုက်ပျိုးရန်။\r\n • ရေထိန်းပေးခြင်းလိုသည်\r\n'),
(13, 'Kiss Me ပန်း ', 'kissme.png', 10000, 50, 'Rainy Season', 'Kiss Me ဟု လူသိများသည့် ပန်း သည် မြန်မာနိုင်ငံတွင်   “ခစ်စ်မီပန်း” ဟုပင် လူသိများသည်။ ပန်းကလေးများမှာ တစ်လှည့်စီ ပွင့်တတ်ပြီး သက်တံ့ရောင်စုံလှပသော ပန်းတစ်မျိုး ဖြစ်သည်။\r\n\r\n မြေအနေအထား\r\n • အပူပိုင်းဒေသများ တွင် အလွန်ကောင်းမွန်စွာ ကြီးထွားနိုင်သည်။\r\n • နေရောင်လုံလောက်သော နေရာများတွင် ပိုမိုကြီးထွားမှုကောင်းသည်။\r\n • မြေစိုစွတ်မှုအနည်းငယ်ရှိ၍ ရေစိမ့်နိုင်သော မြေတွင် ပိုမိုသင့်တော်သည်။\r\n • အရိပ်ကျသောနေရာများတွင် ကြီးထွားနိုင်သော်လည်း နေရောင်ရသည့်နေရာမှာ ပိုကောင်းသည်။\r\n\r\n ပွင့်ချိန်\r\n • တစ်နှစ်ပတ်လုံးပွင့်နိုင်သော်လည်း မိုးရာသီ (မေ – အောက်တိုဘာ) တွင် ပိုမိုပွင့်သည်။\r\n • နွေရာသီ (မတ် – မေ) တွင်လည်း ပွင့်နိုင်သော်လည်း ရေပေးမှုလိုအပ်သည်။\r\n • ပွင့်ချိန်ကာလသည် ရာသီဥတုအပူချိန်နှင့်ပတ်သက်၍ အနည်းငယ်ကွဲပြားနိုင်သည်။\r\n\r\n ရာသီနှင့် အသုံးဝင်မှု\r\n • မိုးရာသီနှင့် နွေဦးကာလများတွင် ပွင့်သောပန်း ဖြစ်သည်။\r\n • အိမ်ခြံဝန်းများ၊ ပန်းခြံများတွင် အလှဆင်ရန် အသုံးများသည်။\r\n • ပန်းရောင်စုံဖြင့် ပွင့်သည့်အတွက် ချစ်စရာကောင်းသောပန်းဖြစ်သည်။\r\n • ပန်းပွင့်ချိန်မှာ ကြာရှည်ပြီး တစ်ပင်တည်းကပင် ပန်းရောင်စုံပွင့်နိုင်သည်။\r\n\r\n စိုက်ပျိုးခြင်းနှင့် ပြုစုနည်း\r\n • နေရောင်လုံလောက်သော နေရာတွင် စိုက်ပျိုးရန်\r\n • မြေစိုစွတ်မှုကို ထိန်းသိမ်းရန် \r\n • မြေသားအာဟာရဖြည့်ရန် သဘာဝမြေဩဇာ (Organic Compost) ထည့်နိုင်သည်။\r\n • ပန်းများ ပိုမိုပွင့်စေရန် တစ်နှစ်တစ်ကြိမ်ကိုင်းဖြတ်ခြင်း ပြုလုပ်နိုင်သည်။\r\n\r\n'),
(14, 'စက္ကူပန်း ', 'sat.png', 9000, 50, 'Cold Season', 'စက္ကူပန်းသည်  ခြံတိုင်အလှပန်းပင်တစ်မျိုး ဖြစ်ပြီး အပူပိုင်းဒေသများတွင် အလွန်ကြီးထွားမှုကောင်းသည်။\r\n\r\n မြေအနေအထား\r\n • နေရောင်အပြည့်ရရှိလျှင် ကြီးထွားမှုကောင်းသည်။ \r\n • ရေစိုစွတ်မှု လိုအပ်ချက်နည်းသည် (မြေလုံလောက်ပြီးရေစိမ့်ကောင်းသောနေရာများတွင် ပိုမိုသင့်တော်သည်)။\r\n • သဲမြေ၊ ရေဆင်းမြေမျိုးတွင် ပိုမိုကြီးထွားသည်။\r\n\r\n ပွင့်ချိန်\r\n • တစ်နှစ်ပတ်လုံး ပွင့်နိုင်သော်လည်း နွေရာသီ (မတ်-မေ) နှင့် ဆောင်းဦး (နိုဝင်ဘာ-ဇန်နဝါရီ) တွင် ပိုမိုပွင့်သည်။\r\n • မိုးရာသီတွင် ပွင့်မှုနည်းနိုင်သည်။ \r\n • ပန်းပွင့်ချိန်မှာ ရာသီအလိုက် ပြောင်းလဲနိုင်သည်။\r\n\r\n ရာသီနှင့် အသုံးဝင်မှု\r\n • နွေရာသီနှင့် ဆောင်းဦးမှာ ပွင့်လှသောပန်း ဖြစ်သည်။\r\n • ခြံတိုင်များ၊ ဗီလာ၊ ဟိုတယ်များတွင် အလှဆင်ရန် အသုံးများသည်။\r\n • အိမ်ပန်းခြံများတွင်လည်း လူကြိုက်များသည်။\r\n • အပူပိုင်းဒေသများတွင် အလှဆင်ရန် အလွန်သင့်တော်သည်။\r\n\r\n စိုက်ပျိုးခြင်းနှင့် ပြုစုနည်း\r\n • အပူပိုင်းဒေသများတွင် ကြီးထွားကောင်းသည်။\r\n • နေရောင်လုံလောက်သောနေရာတွင် စိုက်ပျိုးရန်။\r\n • ရေထိန်းပေးခြင်းလိုသည် (အလွန်များမဖြစ်စေသင့်)။\r\n • ပန်းများ ပိုမိုပွင့်စေရန် နှစ်စဉ် ကိုင်းဖြတ်ပေးရန်  လိုသည်။\r\n \r\n နောက်ထပ် အသုံးဝင်မှု\r\n • ခြံတိုင်အလှဆင်မှုတွင် အလွန်သင့်တော်သည်။\r\n • အိမ်ပန်းခြံများတွင် ချယ်ကပ်စိုက်ပျိုးနိုင်သည်။\r\n • ပန်းစုံရောင်စုံရှိသဖြင့် မင်္ဂလာပွဲများတွင်လည်း အသုံးပြုနိုင်သည်။\r\n • အပူပိုင်းဒေသများတွင် များစွာပွင့်နိုင်ပြီး အလှပန်းပင်များထဲတွင် လူကြိုက်များသည်။\r\n'),
(15, 'ဇော်မွားပန်း', 'zaw.png', 8000, 50, 'Rainy Season', 'ဇော်မွားပန်း သည်  လူကြိုက်များပြီး နွေရာသီနှင့် ဆောင်းဦးရာသီများတွင် ပွင့်လန်းလှပသောပန်းမျိုးဖြစ်သည်။\r\n\r\n မြေအနေအထား\r\n • နေရောင်လှုံလောက်စွာရရှိရန်လိုအပ်သည်။\r\n • ရေဆင်းမြေ၊ အနည်းငယ်သဲပါသော မြေတွင် ပိုမိုကြီးထွားသည်။\r\n\r\n ပွင့်ချိန်\r\n • နွေဦး (မတ်-မေ) နှင့် ဆောင်းဦး (စက်တင်ဘာ-နိုဝင်ဘာ) များတွင် ပိုပွင့်သည်။\r\n • အပူပိုင်းဒေသများတွင် တစ်နှစ်ပတ်လုံး ပွင့်နိုင်သော်လည်း အပူကြီးလွန်းလျှင် ပန်းပွင့်မှုနည်းနိုင်သည်။\r\n • ပန်းပွင့်ချိန်ကို ရှည်ကြာချင်လျှင် ကိုင်းဖြတ်ခြင်း  ပြုလုပ်နိုင်သည်။\r\n\r\n ရာသီနှင့် အသုံးဝင်မှု\r\n • အေးမြသောရာသီတွင် ပိုမိုတည်တံ့ပြီး နွေရာသီတွင် အနည်းငယ်ခံနိုင်ရည်ကျနိုင်သည်။\r\n • ခြံဝင်းများ၊ ပန်းခြံများတွင် အလှဆင်ရန် အသုံးများသည်။\r\n • မင်္ဂလာပွဲပန်းအနေနှင့်လည်း လူကြိုက်များသည်။\r\n • မွှေးကြိုင်သောကြောင့် အနံ့သာယာမှုကိုလည်း ပေးနိုင်သည်။\r\n\r\nစိုက်ပျိုးခြင်းနှင့် ပြုစုနည်း\r\n • နေရောင်လှုံလောက်မှု လိုအပ်သည်။\r\n • မြေစိုစွတ်မှုကို ထိန်းပေးရန် လိုသည် ။\r\n • ပန်းပွင့်မှုတိုးစေရန် နှစ်စဉ်ကိုင်းဖြတ်ရန် လိုသည်။\r\n\r\n'),
(16, 'မိုးမခပန်း', 'moe.png', 10000, 50, 'Cold Season', 'မိုးမခပန်း\r\n\r\n မြေအနေအထား\r\n • နေရောင်ရသောနေရာတွင် ပိုမိုကြီးထွားသည် ။\r\n • ရေဆင်းမြေကို ကြိုက်သည်။\r\n • အပူပိုင်းဒေသများတွင် အထူးလှပသည်။\r\n\r\n ပွင့်ချိန်\r\n • ဆောင်းဦး (နိုဝင်ဘာ - မတ်) နှင့် နွေဦး (ဧပြီ - မေ) တွင် ပိုမိုပွင့်လန်းသည်။\r\n ပြုစုနည်း\r\n • ရေပြတ်လပ်မှုမဖြစ်စေရန် ပုံမှန် ရေပေးရန်လိုသည်။\r\n • ပင်ခိုင်ခံ့မှု တိုးစေရန် ကိုင်းဖြတ်ခြင်း ပြုလုပ်ရန်လိုသည်။\r\n • မြေဆီထည့်ခြင်းဖြင့် အာဟာရဖြည့်စွမ်းပေးနိုင်သည်။\r\n • အပူပိုင်းနှင့် အအေးပိုင်းရာသီများကို တိုက်ရိုက် ခံနိုင်ရည်ရှိသည်။\r\n\r\n အသုံးဝင်မှုနှင့် အားသာချက်များ\r\n • အိမ်တွင်း၊ ခြံဝင်းများတွင် အလှဆင်ရန် အထူးသင့်တော်သည်။\r\n • ပန်းရောင်စုံလင်မှုကြောင့် မင်္ဂလာပွဲများတွင်လည်း အသုံးများသည်။\r\n\r\n'),
(17, 'ခြောက်လပန်း', '6.png', 8000, 50, 'Hot Season', 'ခြောက်လပန်း သည်နွေရာသီများတွင် ပွင့်သော ပန်းဖြစ်ပြီး မြေအကြောင်းအရာအပေါ် မူတည်၍ ပန်းအရောင် ပြောင်းလဲနိုင်ခြင်းသည် ၎င်း၏ ထူးခြားချက်ဖြစ်သည်။\r\n\r\n မြေအနေအထား\r\n • ခြောက်သွေ့သောမြေထက် အနည်းငယ်စိုစွတ်သော မြေတွင် ပိုမိုကြီးထွားသည်။\r\n • နေ့ခင်းပိုင်းတွင် နေရောင်အပြည့်မထိရအောင် အမိုး ကာထားခြင်း သို့မဟုတ် \r\n     အနည်းငယ်ရိပ်သောနေရာတွင် စိုက်ပျိုးရန်။\r\n • မြေလွှာ အပူချိန် အေးမြသောနေရာတွင် ပိုမိုပွင့်လန်းသည်။\r\n\r\n ပွင့်ချိန်\r\n • နွေဦး (မတ် - မေ) နှင့် နွေရာသီ (ဇွန် - ဩဂုတ်) တွင် ပွင့်လန်းသည်။\r\n • အပင်အရွယ်အစားကြီးလာလျှင် တစ်နှစ်ပတ်လုံးပွင့်နိုင်သည်။\r\n • မြေ၏ အက်စစ်မှု (pH) ပေါ်မူတည်၍ ပန်းအရောင် ပြောင်းလဲနိုင်သည် ။(pH အနိမ့် - အပြာရောင်၊ pH အမြင့် - ပန်းရောင်)\r\n\r\n ပြုစုနည်း\r\n • အပင်ကို များများဖြတ်တောက်ခြင်း မလုပ်ပါနှင့်၊ အပင်သည် အရွယ်ရလာမှ ပန်းများ ပွင့်နိုင်သည်။\r\n • စိုစွတ်မှုကို ထိန်းသိမ်းရန် ပုံမှန် ရေပေးရန် ။\r\n • ပျိုးမြေဆီထည့်ခြင်းဖြင့် ပန်းပွင့်မှုကို မြှင့်တင်နိုင်သည်။\r\n • မြေ၏ pH အလိုက် ပန်းအရောင်ပြောင်းလဲမှုကို စမ်းသပ်နိုင်သည်။\r\n\r\n'),
(18, 'ကြည်ပြာပန်း', 'kyi.png', 10000, 50, 'Rainy Season', 'ကြည်ပြာပန်း\r\n မြေအနေအထား\r\n • နေရောင်ကို ကြိုက်သဖြင့် နေရောင် အပြည့်ရနိုင်သောနေရာတွင် စိုက်ပျိုးရန်။\r\n • ရေစိုစွတ်မှု လုံလောက်သော မြေတွင် ပိုမိုကြီးထွားသည်။\r\n • မြေစိုစွတ်မှုကို ထိန်းထားရန် အပင်များဖြင့်ပြုလုပ်ထားသော မြေဆွေးထည့်နိုင်သည်။\r\n\r\n ပွင့်ချိန်\r\n • နွေရာသီ (မေ - သြဂုတ်) နှင့် ဆောင်းဦး (စက်တင်ဘာ - အောက်တိုဘာ) တွင် ပွင့်သည်။\r\n • မိုးရာသီ (ဇွန် - စက်တင်ဘာ) တွင်လည်း အနည်းငယ် ပွင့်နိုင်သည်။\r\n • နံနက်ပိုင်းတွင် ပွင့်ပြီး နေ့လယ်ပိုင်းကျော်သည်နှင့် ပန်းညိုးရော်သွားတတ်သည်။\r\n\r\n. အသုံးဝင်မှုနှင့် အားသာချက်များ\r\n • အိမ်ခြံဝင်းများကို အလှဆင်ရန် သင့်တော်သည်\r\n• ပန်းပွင့်ချိန်တိုသော်လည်း နံနက်ပိုင်းအလှဆုံး ဖြစ်ခြင်းကြောင့် “Morning Glory” ဟုခေါ်သည်။\r\n'),
(19, 'စံပယ်ပန်း', 'sapal.jpg', 7000, 50, 'Cold Season', ' စံပယ်ပန်း                       \r\n  မြေဆွေးအနေအထား\r\n • စံပယ်ပန်းသည် ရေစိမ့်နိုင်မှုကောင်းမွန်သော မြေတွင်စိုက်ရပါမည်။\r\n • ဥပမာ - သဲမြေ၊ အစိုဓာတ်ရှိပြီး ရေမြုပ်မကျန်သောမြေမျိုးတွင် ကြီးထွားနိုင်သည်။\r\n\r\n နေရောင်ခြည်နှင့် ရာသီဥတု\r\n • နေရောင်လုံလောက်စွာလိုအပ်သည်။ \r\n• အေးလွန်းသောနေရာများတွင် ခြောက်သွေ့နိုင်သည်။\r\n \r\n ရာသီဥတုနှင့်ပန်းပွင့်ချိန်\r\n • စံပယ်ပန်းသည် တစ်နှစ်ပတ်လုံးပန်းပွင့်နိုင်သော်လည်း နွေရာသီနှင့် ဆောင်းဦးရာသီ (မေလမှ အောက်တိုဘာ) တွင် ပန်းပိုမိုပွင့်လေ့ရှိသည်။\r\n \r\nရေဓာတ်နှင့်စိုက်ပျိုးနည်း\r\n • ရေသုံးစွဲမှု အလယ်အလတ် (သို့) နေ့စဉ် တစ်ကြိမ် သို့မဟုတ် နှစ်ရက်တစ်ကြိမ် ရေပေးသင့်သည်။\r\n • မိုးလေဝသပေါ်မူတည်၍ ရေပေးရမည်။\r\n • စိုက်ပျိုးရာတွင် အပင်ကြား အကွာအဝေး ကောင်းမွန်စွာထားပေးရန် လိုအပ်သည်။\r\n \r\nထိန်းသိမ်းမှု\r\n • သက်တမ်းကြာလာသည်နှင့်အမျှ ရင့်ဆွေးနေသော သစ်ခက်များကို ဖြတ်ထွင်းရန် လိုအပ်သည်။\r\n • သဘာဝအော်ဂဲနစ်မြေသြဇာ တို့ဖြင့် စိုက်ခြင်းက ပန်းပိုပွင့်နိုင်သည်။\r\n'),
(20, 'ထိုင်းစံပယ်ပန်း', 'thai.png', 10000, 50, 'Rainy Season', 'ထိုင်းစံပယ်ပန်း\r\n\r\nထိုင်းစံပယ်ပန်းသည် ထိုင်း၊ မြန်မာ၊ အိန္ဒိယနှင့် အာရှနိုင်ငံများတွင် လူကြိုက်များသော ပန်းဖြစ်သည်။\r\n\r\nမြေအနေအထား\r\nထိုင်းစံပယ်ပန်းသည် အပူပိုင်းဒေသများတွင် ပေါက်ရောက်နိုင်သည်။\r\n • စိုစွတ်သော မြေများ၊ ရေစီးကောင်းသော မြေများတွင် ပိုမိုပေါက်ရောက်နိုင်သည်။\r\n • သဲမြေ၊ နွံမြေများတွင် ပျိုးထောင်နိုင်သော်လည်း စိုထိုင်းဆ လုံလောက်မှုလိုအပ်သည်။\r\n • နေရောင်ရရှိပြီး မိုးရွာမှုနှုန်း ပျမ်းမျှကောင်းမွန်သော နေရာများတွင် ပိုမိုဖြစ်ထွန်းသည်။\r\n\r\nပွင့်သောရာသီ\r\nထိုင်းစံပယ်ပန်းသည် တစ်နှစ်ပတ်လုံး ပန်းပွင့်နိုင်သော်လည်း နွေဦးနှင့် မိုးရာသီ (မတ် - စက်တင်ဘာ) အတွင်း ပိုမိုသိသာစွာ ပွင့်လန်းသည်။\r\n • အပူချိန် ၂၅-၃၅°C အတွင်း ရှိလျှင် ပိုမိုပြည့်စုံစွာ ပွင့်နိုင်သည်။\r\n • ရေငန်မှုနည်းသော မြေများတွင် ပိုမိုကောင်းမွန်စွာ ပွင့်နိုင်သည်။\r\n\r\nပန်းရောင်နှင့် ပန်းပွင့်သဏ္ဍာန်\r\n • ထိုင်းစံပယ်ပန်းသည် အဖြူနုရောင်နှင့် အဝါနုရောင်ပါဝင်သော ပန်းတစ်မျိုးဖြစ်သည်။\r\n• နုမြူစံပယ်ပန်း နှင့် ဆင်တူသော်လည်း အပွင့်သဏ္ဍာန်သည် သာမန်စံပယ်ပန်းထက် ပိုကြီးသည်။\r\n \r\nအသုံးချမှုများ\r\n • မွှေးကြိုင်မှုကြောင့် ရေမွေးထုတ်လုပ်မှု  တွင် အသုံးများသည်။\r\n • ပန်းကို ရေမွေးထုတ်လုပ်ခြင်းနှင့် ဆေးဖက်ဝင်ပစ္စည်းများတွင် အသုံးပြုနိုင်သည်။\r\n• ရိုးရာဆေးတစ်ချို့တွင် အသုံးပြုနိုင်ပြီး ကိုယ်အပူချိန်ကျဆေးအဖြစ်လည်း သုံးနိုင်သည်။\r\n'),
(21, 'မလေးစကားအထပ်ပန်း', 'malay.png', 10000, 50, 'Rainy Season', 'မလေးစကားအထပ်ပန်း \r\nမြေအနေအထား\r\nမလေးစကားအထပ်ပန်းသည် အပူပိုင်းဒေသများတွင် ပေါက်ရောက်နိုင်ပြီး အပူချိန်မြင့်မားသော နေရာများကိုနှစ်သက်သည်။\r\n • အမြဲစိုစွတ်နေသော မြေအမျိုးများ (သစ်တောဧရိယာ၊ မြစ်ဝကျွန်းပေါ်များ) တွင်ပင် ပေါက်နိုင်သည်။\r\n • မြေညစ်ညမ်းမှုနည်းပြီး၊ သဲမြေထဲတွင်မှန်ကန်သော စိုထိုင်းဆပမာဏရှိရမည်။\r\n • ပန်းခြံနှင့် ပန်းဥယျာဉ်များတွင် အလှပန်းအဖြစ်စိုက်ပျိုးလေ့ရှိသည်။\r\n\r\nပွင့်သောရာသီ\r\nမလေးစကားအထပ်ပန်းသည် နွေဦးနှင့် မိုးရာသီအစောပိုင်း (မတ် - ဇွန်) တွင် ပွင့်သည်။\r\n • တချို့ဒေသများတွင် တစ်နှစ်ပတ်လုံးပန်းပွင့်နိုင်သော်လည်း မတ်လမှ ဇူလိုင်လအထိ ပန်းများ ပိုမိုပွင့်နိုင်သည်။\r\n\r\nပန်းရောင်နှင့် ပန်းပွင့်သဏ္ဍာန်\r\n • နီရောင်၊ လိမ္မော်ရောင်များ ပါဝင်သည့် ပန်းကြီးများဖြင့် ထင်ရှားသည်။\r\n • တစ်ပွင့်တည်းအနေနဲ့မဟုတ်ပဲ အထပ်ထပ်ပွင့်သော ပန်းအစုအဝေးကြီး တစ်ခုလို ဖြစ်သည်။\r\n • ကြက်ခြေနီသံပုရာပန်းနှင့် ဆင်တူသော်လည်း ပိုမိုပွင့်လန်းပြီး ကြီးမားသည်။\r\n\r\nအသုံးချမှုများ\r\n • အလှပန်းအဖြစ် လမ်းဘေး၊ ဥယျာဉ်များတွင်စိုက်ပျိုးသည်။\r\n • ခြံတစ်ဝိုက်အပူချိန်လျှော့ချနိုင်သော သစ်ပင် တစ်မျိုးဖြစ်သည်။\r\n • စိုက်ပျိုးရလွယ်ကူပြီး ဗိုင်းရပ်စ်နှင့် ပိုးမွှားများကို ခံနိုင်ရည်ရှိသည်။\r\n • ငှက်များနှင့် ပျားများကို ဆွဲဆောင်သော ပန်းဖြစ်သည်။\r\n\r\n'),
(22, 'ခိုင်ရွှေဝါပန်း', 'kaing.png', 12000, 50, 'Rainy Season', 'ခိုင်ရွှေဝါပန်း \r\nခိုင်ရွှေဝါပန်းသည် မြန်မာနိုင်ငံတွင်သာမက အိန္ဒိယ၊ ထိုင်းနှင့် အရှေ့တောင်အာရှနိုင်ငံများတွင်လည်း တွေ့ရသည်။\r\n\r\nမြေအနေအထား\r\nခိုင်ရွှေဝါပန်းသည် အပူပိုင်းဒေသများတွင် ကောင်းမွန်စွာပေါက်နိုင်ပြီး နွံမြေ၊ သဲမြေ၊ အစိုဓာတ်နည်းသောမြေများတွင်ပင် ရှင်သန်နိုင်သည်။ အပူပိုင်း နေရာများတွင် အထူးသင့်တော်သည်။\r\n\r\nပွင့်သောရာသီ\r\nခိုင်ရွှေဝါပန်းသည် နွေဦးနှင့် မိုးဝင်ချိန် (ဧပြီ - ဇွန်လ) များတွင် ပွင့်လန်းသည်။ တချို့ဒေသများတွင် မတ်လလောက်မှစတင်ပြီး ဇူလိုင်လအထိ ပန်းပွင့်နိုင်သည်။\r\n\r\nပန်းရောင်နှင့် ပန်းပွင့်သဏ္ဍာန်\r\n • ခိုင်ရွှေဝါပန်းသည် အဖြူနုရောင်နှင့် ရွှေရောင်များပါဝင်သည့် အလှပဆုံးပန်းတစ်မျိုးဖြစ်သည်။\r\n • အလှတရားကြောင့် လမ်းဘေးများတွင်စိုက်ပျိုးသည်။\r\n\r\nအသုံးချမှုများ\r\n • ဆေးဖက်ဝင်အပင်ဖြစ်သည် – ပင်စည်၊ အရွက်၊ အခွံ နှင့် အမြစ်များကို ဆေးဝါးထုတ်လုပ်ရာတွင် အသုံးပြုနိုင်သည်။\r\n • မိုးရာသီမတိုင်မီ ပွင့်သဖြင့် မိုးခေါ်ပန်း ဟုလည်း ခေါ်ကြသည်။\r\n • အိန္ဒိယတွင် ခိုင်ရွှေဝါပန်းကို နတ်ထုံးပန်း အဖြစ်ယူဆကြသည်။\r\n\r\n'),
(23, 'ပုံဏ္ဏရိပ်ပန်း ', 'pont.png', 6000, 50, 'Cold Season', 'ပုံဏ္ဏရိပ်ပန်း သည် မြန်မာ၊ အိန္ဒိယ၊ ထိုင်းနှင့် အာရှအပူပိုင်းဒေသများတွင် သဘာဝအတိုင်းလည်းကောင်း၊ စိုက်ပျိုးမှုအားဖြင့်လည်းကောင်း တွေ့နိုင်သည်။\r\n\r\nမြေအနေအထား\r\nပုံဏ္ဏရိပ်ပန်း သည် အပူပိုင်းဒေသများတွင် ပိုမိုပေါက်ရောက်နိုင်သည်။\r\n • ခြောက်သွေ့သောဒေသများတွင် တောင်တန်းပေါ်ကအစ တောအတွင်းအထိ တွေ့ရနိုင်သည်။\r\n • စိုစွတ်သောမြေများ၊ ရေချိုင့်မြေများနှင့်လည်း ခံနိုင်ရည်ရှိသည်။\r\n • သဲမြေ၊ နွံမြေ၊ ညစ်ညမ်းသောမြေများတွင်လည်း  သက်တမ်းရှည်စိုက်ပျိုးနိုင်သည်။\r\n • ကမ်းရိုးတန်းနှင့် မြစ်ဝကျွန်းပေါ်များတွင်လည်း တွေ့နိုင်သည်။\r\n\r\nပွင့်သောရာသီ\r\nပုံဏ္ဏရိပ်ပန်း သည် နွေဦးနှင့် မိုးဝင်ချိန် (မတ် - ဇွန်) တွင် ပွင့်သည်။\r\n • အပူချိန် ၂၅-၃၅°C အတွင်းရှိသည့်ဒေသများတွင် ပို ပွင့်သည်။\r\n\r\nပန်းရောင်နှင့် ပန်းပွင့်သဏ္ဍာန်\r\n • ပုံဏ္ဏရိပ်ပန်း သည်  ခရမ်းနုရောင်သို့မဟုတ် အဝါနုရောင် ရှိသော ပန်းတစ်မျိုးဖြစ်သည်။\r\n • ပုလဲပန်းပုံသဏ္ဍာန်နှင့် ဆင်တူသော ပန်းများ ဖြစ်သည်။\r\n • အုပ်စုလိုက်ပွင့်သော ပန်းပွင့်သဏ္ဍာန်ရှိပြီး မွှေးကြိုင်မှု အနည်းငယ်ပါဝင်သည်။\r\n\r\nအသုံးချမှုများ\r\n • အမိုးအကာပင်အဖြစ် အသုံးများသည် – လမ်းဘေး၊ အများသုံးဥယျာဉ်များတွင် များစွာ တွေ့နိုင်သည်။\r\n • ညစ်ညမ်းသောမြေများကို သဘာဝပြန်လည်သန်စွမ်းမှုရှိစေသည် ။\r\n • ဆေးဖက်ဝင်အပင်ဖြစ်သည် – အရွက်၊ အမြစ်များကို ဆေးဖက်ဝင်ကုထုံးများတွင် အသုံးပြုသည်။\r\n • စိုက်ပျိုးရလွယ်ကူပြီး၊ ရှင်သန်မှုကြာရှည်သော အပင်ဖြစ်သည်။\r\n • နံ့သာနံ့အနေနဲ့ ပြုလုပ်၍ သုံးနိုင်သည်။\r\n'),
(24, 'နှဲပန်း', 'nall.png', 8000, 50, 'Rainy Season', 'နှဲပန်းသည် လူသိများပြီး မြန်မာ၊ အိန္ဒိယနှင့် အာရှအပူပိုင်းဒေသများတွင် သဘာဝအတိုင်းလည်းကောင်း၊ စိုက်ပျိုးမှုအားဖြင့်လည်းကောင်း တွေ့နိုင်သည်။\r\n\r\nမြေအနေအထား\r\nနှဲပန်းသည် အပူပိုင်းရာသီရှိသော ဒေသများတွင် ပိုမိုပေါက်ရောက်နိုင်သည်။\r\n • ခြောက်သွေ့သောမြေများ၊ သဲမြေများ၊ ကျွန်းမြေများတွင် ပိုမိုပေါက်ရောက်နိုင်သည်။\r\n • ရေချိုင့်မြေများနှင့်လည်း ခံနိုင်ရည်ရှိသော်လည်း အလွန်စိုထိုင်းသောနေရာများတွင် မကြီးထွားနိုင်ပါ။\r\n\r\nပွင့်သောရာသီ\r\nနှဲပန်းသည် နွေဦးနှင့် မိုးဝင်ချိန် (ဖေဖော်ဝါရီ - ဧပြီ) အတွင်း ပန်းပွင့်လန်းသည်။\r\n • ပန်းပွင့်ချိန်တွင် သစ်ရွက်များ ညိုးရော်ကျပြီး ပန်းသာလျှင်ပွင့်လျှံနေခြင်းသည် နှဲပန်း၏ ထူးခြားမှုဖြစ်သည်။\r\n • မိုးရာသီမတိုင်မီ အထူးပွင့်လန်းပြီး တစ်ခါတည်းပွင့်လျှံသွားသည်။\r\n • မြန်မာနိုင်ငံတွင် ဧရာဝတီတိုင်းနှင့် တောင်ငူဒေသများတွင် သဘာဝအတိုင်းများပြားစွာ တွေ့နိုင်သည်။\r\n\r\nအရောင်နှင့် ပန်းပွင့်သဏ္ဍာန်\r\n • နှဲပန်းသည် လောင်ကျွမ်းနေသည့် မီးတောင်လို မြင်သာစွာ အနီရင့်သို့မဟုတ် လိမ္မော်ရောင်ပန်းများဖြင့် ထင်ရှားသည်။\r\n • ကြက်ခြေနီသံပုရာပန်းနှင့် ဆင်တူသော ပန်းများဖြင့် အုပ်စုလိုက်ပွင့်လျှံသည်။\r\n • တစ်ပင်လုံးပန်းများနှင့်ပြည့်စုံသဖြင့် “Flame of the Forest” (တောမီးတောက်) ဟု ခေါ်သည်။\r\n\r\nအသုံးချမှုများ\r\n • အလှပန်းအဖြစ် လမ်းဘေး၊ တောကြီးတောင်ကြီးများတွင် သဘာဝအလျောက်ပွင့်နေသည်ကို တွေ့နိုင်သည်။\r\n • ဆေးဖက်ဝင်အပင် – အရွက်နှင့် ပန်းများကို ရိုးရာဆေးများတွင် အသုံးပြုသည်။\r\n• ပိုးသားရောင်ဆိုးခြင်း – ပန်းမှရသော အနီရောင် ဆေးကို ပိုးသားများကို အရောင်ဆိုးရာတွင် အသုံးပြုသည်။\r\n • တောထောင်ခြင်းနှင့် သဘာဝပတ်ဝန်းကျင်ထိန်းသိမ်းမှုအတွက် စိုက်ပျိုးနိုင်သည်။\r\n'),
(25, 'သစ်ခွပန်း', 'khaungyann.jpg', 12000, 50, 'Hot Season', '');

